#include<bits/stdc++.h>
using namespace std;

const int maxn=1e3+550,kd[][2]={{-1,-1},{1,-1},{-1,1},{1,1}};
int n,sx,sy,rx,ry;

struct node{
	int x,y,dir,d;
};

bool vis[maxn][maxn][5];
char c[maxn][maxn];
deque<node>dq;

int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>sx>>sy>>rx>>ry;

	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			cin>>c[i][j];
		}
	}

	dq.push_front({sx,sy,-1,0});

	while(!dq.empty()){
		auto t=dq.front();
		dq.pop_front();

		if(vis[t.x][t.y][t.dir+1]){
			continue;
		}

		if(t.x==rx&&t.y==ry){
			cout<<t.d;
			return 0;
		}

		vis[t.x][t.y][t.dir+1]=1;

		for(int i=0;i<4;i++){
			int tx=t.x+kd[i][0];
			int ty=t.y+kd[i][1];

			if(tx<1||tx>n||ty<1||ty>n||c[tx][ty]!='.'){
				continue;
			}

			if(i==t.dir){
				dq.push_front({tx,ty,i,t.d});
			}else{
				dq.push_back({tx,ty,i,t.d+1});
			}
		}
	}
	cout<<-1;
	return 0;
}
